const raw = $input.first().json;
const body = raw.body || raw;

const cartaoId = String(body.cartao_id || '').trim();
const mesReferencia = String(body.mes_referencia || '').trim();
const faturaUrl = String(body.fatura_url || '').trim();
const arquivoNome = String(body.arquivo_nome || body.file_name || `fatura-${mesReferencia || 'sem-mes'}.pdf`).trim();
const mimeType = String(body.mime_type || 'application/pdf').trim();
const storagePath = String(body.storage_path || '').trim();
const textoExtraido = String(body.texto_extraido || '').trim();
const itensEntrada = Array.isArray(body.itens) ? body.itens : [];

if (!cartaoId) {
  throw new Error('cartao_id obrigatorio');
}
if (!mesReferencia || !/^\d{4}-\d{2}$/.test(mesReferencia)) {
  throw new Error('mes_referencia deve estar no formato YYYY-MM');
}
if (!faturaUrl) {
  throw new Error('fatura_url obrigatoria');
}

return [{
  json: {
    cartao_id: cartaoId,
    mes_referencia: mesReferencia,
    fatura_url: faturaUrl,
    arquivo_nome: arquivoNome,
    mime_type: mimeType,
    storage_path: storagePath,
    texto_extraido: textoExtraido,
    itens_entrada: itensEntrada,
    processado_em: new Date().toISOString()
  }
}];

const input = $input.first().json;
const body = $items('Preparar Entrada', 0, 0)[0].json;
const registro = Array.isArray(input) ? input[0] : input;
const faturaId = registro?.id;

if (!faturaId) {
  throw new Error('Nao foi possivel obter o id da fatura apos o upsert');
}

const itensEntrada = Array.isArray(body.itens_entrada) ? body.itens_entrada : [];
if (itensEntrada.length > 0) {
  const normalizados = itensEntrada
    .map((item) => ({
      data_lancamento: String(item.data_lancamento || '').trim(),
      descricao: String(item.descricao || '').trim(),
      valor: Number(item.valor || 0),
      categoria_banco: item.categoria_banco ? String(item.categoria_banco).trim() : null
    }))
    .filter((item) => item.data_lancamento && item.descricao && Number.isFinite(item.valor) && item.valor > 0);

  return [{
    json: {
      ...body,
      fatura_id: faturaId,
      itens_extraidos: normalizados,
      parser_origem: 'payload_manual'
    }
  }];
}

const texto = String(body.texto_extraido || '').trim();
if (!texto) {
  throw new Error('Configure um node OCR/IA antes deste passo ou envie texto_extraido/itens no payload.');
}

const linhas = texto
  .split(/\r?\n/)
  .map((linha) => linha.replace(/\s+/g, ' ').trim())
  .filter(Boolean);

const itens = [];
for (const linha of linhas) {
  const m = linha.match(/(\d{2}\/\d{2}(?:\/\d{2,4})?)\s+(.+?)\s+(-?\d+[\.,]\d{2})$/);
  if (!m) continue;
  let [_, dataBr, descricao, valorBr] = m;
  const partes = dataBr.split('/');
  const ano = partes.length === 3 ? partes[2] : body.mes_referencia.slice(0, 4);
  const ano4 = ano.length === 2 ? `20${ano}` : ano;
  const dataIso = `${ano4}-${partes[1]}-${partes[0]}`;
  const valor = Number(valorBr.replace(/\./g, '').replace(',', '.'));
  if (!Number.isFinite(valor) || valor <= 0) continue;
  itens.push({
    data_lancamento: dataIso,
    descricao: descricao.trim(),
    valor,
    categoria_banco: null
  });
}

if (itens.length === 0) {
  throw new Error('Nenhum item foi identificado na fatura. Revise o OCR/IA ou envie itens estruturados.');
}

return [{
  json: {
    ...body,
    fatura_id: faturaId,
    itens_extraidos: itens,
    parser_origem: 'texto_extraido'
  }
}];

const itens = $input.first().json;
const itensInseridos = Array.isArray(itens) ? itens : [itens];
const soma = itensInseridos.reduce((acc, item) => acc + Number(item.valor || 0), 0);
const base = $items('Normalizar Itens', 0, 0)[0].json;

return [{
  json: {
    fatura_id: base.fatura_id,
    cartao_id: base.cartao_id,
    mes_referencia: base.mes_referencia,
    arquivo_nome: base.arquivo_nome,
    processado_em: base.processado_em,
    total_itens: itensInseridos.length,
    valor_total: Number(soma.toFixed(2)),
    parser_origem: base.parser_origem
  }
}];

const erro = $input.first().json;
const base = $items('Preparar Entrada', 0, 0)[0].json;
const mensagem = String(erro.message || erro.error?.message || 'Falha ao processar fatura');

return [{
  json: {
    cartao_id: base.cartao_id,
    mes_referencia: base.mes_referencia,
    erro_msg: mensagem,
    processado_em: new Date().toISOString()
  }
}];
